        return None

    def distance(a, b):
        return np.linalg.norm(a - b)

    best_node = None
    min_cost = float('inf')

    # Iterate over each unvisited customer to determine the best next move
    for idx, customer_pos in enumerate(unvisited_customers):
        dist_to_customer = distance(cur_truck_pos, customer_pos)
        total_distance = dist_to_customer + distance(customer_pos, depot_pos)

        # Assume some form of future penalty or cost based on unvisited customers
        potential_cost = total_distance + len(unvisited_customers) * (dist_to_customer / max(len(all_truck_pos), 1))

        if potential_cost < min_cost:
